/**
 * Gemini Live Session
 * Manages a single per-call WebSocket connection to Gemini BidiGenerateContent.
 * Bridges bidirectional audio between Jambonz (L16 PCM) and Gemini (PCM base64).
 */

import { config } from "./config.ts";

// Phase 0 diagnostic: bounded queue + async flusher. Read once at boot;
// toggling requires bridge restart (documented in README).
const DIAG_ENABLED = Deno.env.get("VOICE_DIAG") === "1";
const DIAG_SECRET = Deno.env.get("VOICE_DIAG_SECRET") ?? "";
const DIAG_ENDPOINT = config.supabaseUrl
  ? `${config.supabaseUrl.replace(/\/+$/, "")}/functions/v1/voice-diag`
  : "";
const DIAG_QUEUE_CAP = 200;
const DIAG_FLUSH_MS = 10_000;

type DiagEvent = Record<string, unknown>;
const diagQueue: DiagEvent[] = [];
let diagDropped = 0;

function diagPush(event: DiagEvent): void {
  if (!DIAG_ENABLED || !DIAG_SECRET || !DIAG_ENDPOINT) return;
  if (diagQueue.length >= DIAG_QUEUE_CAP) {
    diagQueue.shift();
    diagDropped++;
  }
  diagQueue.push(event);
}

async function diagFlush(): Promise<void> {
  if (diagQueue.length === 0) return;
  const batch = diagQueue.splice(0, diagQueue.length);
  try {
    await fetch(DIAG_ENDPOINT, {
      method: "POST",
      headers: { "Content-Type": "application/json", "X-Diag-Secret": DIAG_SECRET },
      body: JSON.stringify(batch),
    });
  } catch {
    // discard on failure — no retry
  }
}

if (DIAG_ENABLED && DIAG_SECRET && DIAG_ENDPOINT) {
  setInterval(() => { diagFlush(); }, DIAG_FLUSH_MS);
  console.log("[GeminiSession] VOICE_DIAG enabled (bridge)");
}

function diagUuid(): string {
  return (crypto as any).randomUUID
    ? (crypto as any).randomUUID()
    : `${Date.now()}-${Math.random().toString(36).slice(2)}`;
}

export function diagEmitFromBridge(opts: {
  liveSessionId: string;
  conversationId?: string | null;
  turnId: number;
  conversationTurnCount: number;
  refreshTrigger?: "none" | "turn_count" | "timer" | "reconnect";
  refreshedThisTurn?: boolean;
  vadCommitToFirstAudioMs?: number | null;
  extra?: Record<string, unknown>;
}): void {
  if (!DIAG_ENABLED) return;
  diagPush({
    client_event_id: diagUuid(),
    live_session_id: opts.liveSessionId,
    conversation_id: opts.conversationId ?? null,
    turn_id: opts.turnId,
    conversation_turn_count: opts.conversationTurnCount,
    refresh_trigger: opts.refreshTrigger ?? "none",
    refreshed_this_turn: !!opts.refreshedThisTurn,
    server_prompt_had_history: false,
    vad_commit_to_first_audio_ms: opts.vadCommitToFirstAudioMs ?? null,
    name_adoption_state: "unknown",
    channel: "pstn",
    ts_client: Date.now(),
    extra: { ...(opts.extra ?? {}), diagDropped },
  });
}

function bufferToBase64(buffer: Uint8Array): string {
  let binary = "";
  for (let i = 0; i < buffer.length; i++) {
    binary += String.fromCharCode(buffer[i]);
  }
  return btoa(binary);
}

function base64ToBuffer(b64: string): Uint8Array {
  const binary = atob(b64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes;
}

function uint8ArrayToText(data: Uint8Array): string {
  return new TextDecoder().decode(data);
}

/**
 * Resample L16 PCM from 24kHz to 16kHz using linear interpolation.
 * Gemini outputs 24kHz; Jambonz expects 16kHz.
 */
function resample24kTo16k(input: Uint8Array): Uint8Array {
  // Input is raw bytes of signed 16-bit LE samples at 24kHz
  const inputSamples = new Int16Array(input.buffer, input.byteOffset, input.byteLength / 2);
  const ratio = 24000 / 16000; // 1.5
  const outputLength = Math.floor(inputSamples.length / ratio);
  const outputSamples = new Int16Array(outputLength);

  for (let i = 0; i < outputLength; i++) {
    const srcIndex = i * ratio;
    const srcFloor = Math.floor(srcIndex);
    const frac = srcIndex - srcFloor;

    if (srcFloor + 1 < inputSamples.length) {
      outputSamples[i] = Math.round(
        inputSamples[srcFloor] * (1 - frac) + inputSamples[srcFloor + 1] * frac
      );
    } else {
      outputSamples[i] = inputSamples[srcFloor];
    }
  }

  return new Uint8Array(outputSamples.buffer);
}

async function wsDataToText(data: unknown): Promise<string | null> {
  if (typeof data === "string") return data;

  if (data instanceof Blob) {
    const ab = await data.arrayBuffer();
    return uint8ArrayToText(new Uint8Array(ab));
  }

  if (data instanceof ArrayBuffer) {
    return uint8ArrayToText(new Uint8Array(data));
  }

  if (data instanceof Uint8Array) {
    return uint8ArrayToText(data);
  }

  return null;
}

export type GeminiSessionCallbacks = {
  cid?: string;
  getElapsedMs?: () => number;
  getMsSinceFlush?: () => number;
  onAudio: (pcmBinary: Uint8Array) => void;
  onTranscript: (text: string) => void;
  onInterrupted: () => void;
  onTurnComplete: () => void;
  onError: (error: string) => void;
  onReady: () => void;
  onClose: (code?: number) => void;
  // +logs-3: fired ONCE on the first audio chunk of any model turn.
  // server.ts uses this as the primary "cancel inbound suppression" signal.
  onFirstModelAudio?: () => void;
  // +voice-native-sms-rating: fired with the FULL finalized text after a turn ends.
  // Prefer these over onTranscript for intent detection on completed turns.
  onUserTurnComplete?: (text: string) => void;
  onModelTurnComplete?: (text: string) => void;
};

export class GeminiSession {
  private ws: WebSocket | null = null;
  private callbacks: GeminiSessionCallbacks;
  private isSetupComplete = false;
  private systemInstruction: string;
  private keepaliveTimer: ReturnType<typeof setInterval> | null = null;
  private fullTranscript = "";
  private receivedFirstMessage = false;
  private setupCompleteAt = 0;
  private cid: string;

  // Phase 0 diag identity
  private diagLiveSessionId: string = (crypto as any).randomUUID
    ? (crypto as any).randomUUID()
    : `s_${Date.now()}`;
  private diagTurnId = 0;
  private diagConversationTurnCount = 0;
  diagConversationId: string | null = null;
  // +logs-3: per-turn first-audio flag. Resets on turn_complete / interrupted.
  private firstAudioFiredThisTurn = false;
  // +voice-native: per-turn finalized-text buffers
  private modelTurnBuffer = "";
  private userTurnBuffer = "";

  constructor(systemInstruction: string, callbacks: GeminiSessionCallbacks) {
    this.systemInstruction = systemInstruction;
    this.callbacks = callbacks;
    this.cid = callbacks.cid ?? "n/a";
  }

  /** Returns current Gemini WebSocket state as a readable string. */
  geminiWsState(): string {
    if (!this.ws) return "null";
    switch (this.ws.readyState) {
      case WebSocket.CONNECTING: return "connecting";
      case WebSocket.OPEN: return "open";
      case WebSocket.CLOSING: return "closing";
      case WebSocket.CLOSED: return "closed";
      default: return `unknown(${this.ws.readyState})`;
    }
  }

  private logGeminiEvent(type: string, extra = ""): void {
    const sinceFlush = this.callbacks.getMsSinceFlush?.() ?? -1;
    const sinceSetup = this.setupCompleteAt === 0 ? -1 : Date.now() - this.setupCompleteAt;
    console.log(
      `[gemini_event] cid=${this.cid} type=${type} elapsed_since_flush_ms=${sinceFlush} elapsed_since_setup_ms=${sinceSetup}${extra ? " " + extra : ""}`,
    );
  }

  async connect(): Promise<void> {
    const wsUrl = `${config.geminiWsBase}?key=${config.googleApiKey}`;
    console.log(
      `[GeminiSession] Connecting to ${config.geminiWsBase} model=${config.geminiModel}`,
    );

    return new Promise<void>((resolve, reject) => {
      const timeout = setTimeout(() => {
        console.error("[GeminiSession] Connection timed out after 15s");
        this.close();
        reject(new Error("Gemini connection timed out"));
      }, 15000);

      this.ws = new WebSocket(wsUrl);

      this.ws.onopen = () => {
        console.log("[GeminiSession] WebSocket opened, sending setup...");
        const setupMessage = {
          setup: {
            model: config.geminiModel,
            generationConfig: {
              responseModalities: ["AUDIO"],
              speechConfig: {
                voiceConfig: {
                  prebuiltVoiceConfig: {
                    voiceName: config.voiceName,
                  },
                },
              },
              // +logs-3 soft cap; primary length control is the in-prompt 1-3 sentence rule.
              maxOutputTokens: 300,
            },
            systemInstruction: {
              parts: [{ text: this.systemInstruction }],
            },
            inputAudioTranscription: {},
            outputAudioTranscription: {},
            realtimeInputConfig: {
              automaticActivityDetection: {
                disabled: false,
              },
            },
          },
        };

        this.ws?.send(JSON.stringify(setupMessage));
        console.log("[GeminiSession] Setup message sent");
      };

      this.ws.onmessage = async (event: MessageEvent) => {
        if (!this.receivedFirstMessage) {
          this.receivedFirstMessage = true;

          let preview = "(unknown)";
          if (typeof event.data === "string") {
            preview = event.data.substring(0, 200);
          } else if (event.data instanceof Blob) {
            preview = `(blob size=${event.data.size})`;
          } else if (event.data instanceof ArrayBuffer) {
            preview = `(arraybuffer bytes=${event.data.byteLength})`;
          } else if (event.data instanceof Uint8Array) {
            preview = `(uint8array bytes=${event.data.byteLength})`;
          } else {
            preview = `(${typeof event.data})`;
          }

          console.log(`[GeminiSession] First message received: ${preview}`);
        }

        await this.handleMessage(event, () => {
          clearTimeout(timeout);
          this.startKeepalive();
          resolve();
        });
      };

      this.ws.onerror = (err) => {
        clearTimeout(timeout);
        console.error("[GeminiSession] WebSocket error:", err);
        console.log(`[gemini_ws] cid=${this.cid} state=error close_code=null reason=ws_error elapsed_ms_since_setup=${this.setupCompleteAt === 0 ? -1 : Date.now() - this.setupCompleteAt}`);
        this.callbacks.onError("Gemini WebSocket error");
        reject(new Error("Gemini WebSocket error"));
      };

      this.ws.onclose = (event: CloseEvent) => {
        clearTimeout(timeout);
        this.stopKeepalive();
        const sinceSetup = this.setupCompleteAt === 0 ? -1 : Date.now() - this.setupCompleteAt;
        console.log(
          `[GeminiSession] Closed: code=${event.code} reason="${event.reason}" wasClean=${event.wasClean} setupComplete=${this.isSetupComplete} model=${config.geminiModel}`,
        );
        console.log(
          `[gemini_ws] cid=${this.cid} state=closed close_code=${event.code} reason="${event.reason}" wasClean=${event.wasClean} elapsed_ms_since_setup=${sinceSetup}`,
        );

        if (!this.isSetupComplete) {
          reject(
            new Error(
              `Gemini closed before setup complete: ${event.code} ${event.reason}`,
            ),
          );
        }

        this.callbacks.onClose(typeof event.code === "number" ? event.code : undefined);
      };
    });
  }

  private async handleMessage(
    event: MessageEvent,
    onSetupResolve?: () => void,
  ): Promise<void> {
    try {
      const text = await wsDataToText(event.data);

      if (!text) {
        console.warn("[GeminiSession] Unsupported WS message type");
        return;
      }

      let msg: any;
      try {
        msg = JSON.parse(text);
      } catch {
        console.warn(
          `[GeminiSession] Non-JSON message received: ${text.substring(0, 200)}`,
        );
        return;
      }

      if (msg.setupComplete || msg.sessionUpdate || msg.serverContent !== undefined) {
        if (!this.isSetupComplete) {
          this.isSetupComplete = true;
          this.setupCompleteAt = Date.now();
          console.log("[GeminiSession] Setup complete");
          console.log(`[gemini_ws] cid=${this.cid} state=open close_code=null reason=setup_complete elapsed_ms_since_setup=0`);
          this.callbacks.onReady();
          onSetupResolve?.();

          if (!msg.serverContent) return;
        }
      }

      if (msg.serverContent) {
        const content = msg.serverContent;

        // Buffer finalized user-side transcription if Gemini emits one.
        // Schema may surface as content.inputTranscription.text or .transcription.text.
        const userTxt =
          content.inputTranscription?.text ??
          content.transcription?.text ??
          null;
        if (typeof userTxt === "string" && userTxt.length > 0) {
          this.userTurnBuffer += (this.userTurnBuffer ? " " : "") + userTxt;
        }

        if (content.interrupted) {
          this.logGeminiEvent("interrupted");
          this.firstAudioFiredThisTurn = false;
          // Flush any partial model-turn buffer to user-turn-complete consumers as well.
          if (this.userTurnBuffer) {
            try { this.callbacks.onUserTurnComplete?.(this.userTurnBuffer); } catch { /* noop */ }
            this.userTurnBuffer = "";
          }
          this.modelTurnBuffer = "";
          this.callbacks.onInterrupted();
          return;
        }

        if (content.turnComplete) {
          this.logGeminiEvent("turn_complete");
          this.diagTurnId += 1;
          this.diagConversationTurnCount += 1;
          diagEmitFromBridge({
            liveSessionId: this.diagLiveSessionId,
            conversationId: this.diagConversationId,
            turnId: this.diagTurnId,
            conversationTurnCount: this.diagConversationTurnCount,
            refreshTrigger: "none",
            refreshedThisTurn: false,
          });
          this.firstAudioFiredThisTurn = false;
          // Fire turn-complete callbacks with finalized text BEFORE generic onTurnComplete.
          if (this.userTurnBuffer) {
            try { this.callbacks.onUserTurnComplete?.(this.userTurnBuffer); } catch { /* noop */ }
            this.userTurnBuffer = "";
          }
          if (this.modelTurnBuffer) {
            try { this.callbacks.onModelTurnComplete?.(this.modelTurnBuffer); } catch { /* noop */ }
            this.modelTurnBuffer = "";
          }
          this.callbacks.onTurnComplete();
          return;
        }

        if (content.modelTurn?.parts) {
          for (const part of content.modelTurn.parts) {
            if (part.inlineData?.data) {
              const pcm24k = base64ToBuffer(part.inlineData.data);
              const pcm16k = resample24kTo16k(pcm24k);
              this.logGeminiEvent("audio", `bytes=${pcm16k.length}`);
              if (!this.firstAudioFiredThisTurn) {
                this.firstAudioFiredThisTurn = true;
                try { this.callbacks.onFirstModelAudio?.(); } catch { /* never throw on hot path */ }
              }
              this.callbacks.onAudio(pcm16k);
            }

            if (part.text) {
              this.fullTranscript += `${part.text} `;
              this.modelTurnBuffer += (this.modelTurnBuffer ? " " : "") + part.text;
              this.logGeminiEvent("transcript", `chars=${part.text.length}`);
              this.callbacks.onTranscript(part.text);
            }
          }
        }
      }
    } catch (err) {
      console.warn("[GeminiSession] Failed to parse message:", err);
    }
  }

  sendAudio(pcmBinary: Uint8Array): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN || !this.isSetupComplete) {
      return;
    }

    const b64 = bufferToBase64(pcmBinary);

    try {
      this.ws.send(
        JSON.stringify({
          realtimeInput: {
            audio: {
              data: b64,
              mimeType: "audio/pcm;rate=16000",
            },
          },
        }),
      );
    } catch (err) {
      console.warn("[GeminiSession] sendAudio error:", err);
    }
  }

  /**
   * +logs-3: fire a one-shot synthetic user turn that prompts Gemini to greet first.
   * The text is a system-style instruction (not real caller speech) — the bridge
   * marks downstream handling so this turn does NOT enter conversation_messages,
   * the visible transcript, or the conversation turn counter.
   */
  sendInitialGreeting(promptText: string): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN || !this.isSetupComplete) {
      console.warn("[GeminiSession] sendInitialGreeting: not ready, skipping");
      return;
    }
    try {
      this.ws.send(JSON.stringify({
        clientContent: {
          turns: [{ role: "user", parts: [{ text: promptText }] }],
          turnComplete: true,
        },
      }));
      console.log(`[GeminiSession] greeting prompt sent (chars=${promptText.length})`);
    } catch (err) {
      console.warn("[GeminiSession] sendInitialGreeting error:", err);
    }
  }

  getTranscript(): string {
    return this.fullTranscript.trim();
  }

  private startKeepalive(): void {
    this.stopKeepalive();

    this.keepaliveTimer = setInterval(() => {
      if (!this.ws || this.ws.readyState !== WebSocket.OPEN || !this.isSetupComplete) {
        return;
      }

      try {
        this.ws.send(
          JSON.stringify({
            realtimeInput: {
              audio: {
                data: "",
                mimeType: "audio/pcm;rate=16000",
              },
            },
          }),
        );
      } catch {
        // ignore
      }
    }, 25000);
  }

  private stopKeepalive(): void {
    if (this.keepaliveTimer) {
      clearInterval(this.keepaliveTimer);
      this.keepaliveTimer = null;
    }
  }

  close(): void {
    this.stopKeepalive();

    if (this.ws) {
      this.ws.onopen = null;
      this.ws.onmessage = null;
      this.ws.onerror = null;
      this.ws.onclose = null;

      try {
        this.ws.close();
      } catch {
        // ignore
      }

      this.ws = null;
    }

    this.isSetupComplete = false;
  }

  get connected(): boolean {
    return this.ws?.readyState === WebSocket.OPEN && this.isSetupComplete;
  }
}

supabase-logger.ts:
/**
 * Supabase REST Logger
 * Logs call metadata, transcripts, and contacts to Supabase via REST API.
 */

import { config } from "./config.ts";

const headers = (): Record<string, string> => ({
  "Content-Type": "application/json",
  apikey: config.supabaseServiceKey,
  Authorization: `Bearer ${config.supabaseServiceKey}`,
  Prefer: "return=representation",
});

const rest = (table: string): string => `${config.supabaseUrl}/rest/v1/${table}`;

export interface VoiceBotConfig {
  greeting_message: string;
  mode: string;
  greeting_language: string;
}

interface KbArticle {
  title: string;
  content: string;
  category: string;
}

export async function fetchVoiceBotConfig(): Promise<VoiceBotConfig | null> {
  try {
    const res = await fetch(
      `${rest("voice_bot_config")}?select=greeting_message,mode,greeting_language&limit=1`,
      { headers: headers() },
    );

    const data = await res.json();
    return data?.[0] ?? null;
  } catch (err) {
    console.error("[Logger] Failed to fetch voice bot config:", err);
    return null;
  }
}

export async function fetchKbArticles(language: string): Promise<string> {
  try {
    const lang = language === "th" ? "th" : "en";

    const res = await fetch(
      `${rest("kb_articles")}?select=title,content,category&is_published=eq.true&language=eq.${lang}&category=neq.bot-core-knowledge&limit=${config.maxKbArticles}`,
      { headers: headers() },
    );

    const articles: KbArticle[] = await res.json();
    if (!articles?.length) return "";

    return `\n\n## KNOWLEDGE BASE ARTICLES\nUse these to answer customer questions accurately:\n${
      articles
        .map((a) => `### ${a.title} (${a.category})\n${a.content.substring(0, 1500)}`)
        .join("\n\n")
    }`;
  } catch (err) {
    console.error("[Logger] Failed to fetch KB articles:", err);
    return "";
  }
}

export async function findOrCreateContact(
  callerNumber: string,
): Promise<string | null> {
  try {
    const res = await fetch(
      `${rest("contacts")}?phone=eq.${encodeURIComponent(callerNumber)}&limit=1`,
      { headers: headers() },
    );

    const existing = await res.json();
    if (existing?.[0]?.id) return existing[0].id;

    const createRes = await fetch(rest("contacts"), {
      method: "POST",
      headers: headers(),
      body: JSON.stringify({
        phone: callerNumber,
        name: callerNumber,
      }),
    });

    const created = await createRes.json();
    return created?.[0]?.id ?? null;
  } catch (err) {
    console.error("[Logger] Contact creation error:", err);
    return null;
  }
}

export async function createConversation(
  contactId: string | null,
): Promise<string | null> {
  try {
    const res = await fetch(rest("conversations"), {
      method: "POST",
      headers: headers(),
      body: JSON.stringify({
        channel: "voice",
        status: "active",
        priority: "normal",
        contact_id: contactId,
        subject: "Voice Bot Call",
      }),
    });

    const data = await res.json();
    return data?.[0]?.id ?? null;
  } catch (err) {
    console.error("[Logger] Conversation creation error:", err);
    return null;
  }
}

export async function createCallLog(params: {
  callId: string;
  callerNumber: string;
  didNumber: string;
  conversationId: string | null;
}): Promise<string | null> {
  try {
    const res = await fetch(rest("voice_call_logs"), {
      method: "POST",
      headers: headers(),
      body: JSON.stringify({
        call_id: params.callId,
        caller_number: params.callerNumber,
        did_number: params.didNumber,
        conversation_id: params.conversationId,
        status: "in_progress",
        started_at: new Date().toISOString(),
        metadata: { source: "jambonz-gemini-bridge" },
      }),
    });

    const data = await res.json();
    return data?.[0]?.id ?? null;
  } catch (err) {
    console.error("[Logger] Call log creation error:", err);
    return null;
  }
}

export async function updateCallLog(
  callLogId: string,
  updates: Record<string, unknown>,
): Promise<void> {
  try {
    await fetch(`${rest("voice_call_logs")}?id=eq.${callLogId}`, {
      method: "PATCH",
      headers: headers(),
      body: JSON.stringify(updates),
    });
  } catch (err) {
    console.error("[Logger] Call log update error:", err);
  }
}

export async function logMessage(
  conversationId: string,
  senderType: "customer" | "ai",
  content: string,
): Promise<void> {
  try {
    await fetch(rest("conversation_messages"), {
      method: "POST",
      headers: headers(),
      body: JSON.stringify({
        conversation_id: conversationId,
        sender_type: senderType,
        content,
        is_internal_note: false,
      }),
    });
  } catch (err) {
    console.error("[Logger] Message log error:", err);
  }
}


// ============================================================
// INLINED FROM bridge-logger.ts — DO NOT MIX WITH TRANSPORT BELOW
// Reason: VPS deploy-agent whitelist rejects new filenames.
// When the whitelist is fixed, extract this section back into
// bridge-logger.ts. Tracking ticket: WHITELIST-BOOTSTRAP.
//
// CONTRACT
//  1. Fail-open. Every helper wraps the Supabase POST in a 1500ms
//     timeout race inside try/catch. Helpers never throw, never
//     reject unhandled. On failure -> console.warn fallback only.
//  2. Non-blocking on hot paths. Callers use `void logStage(...)`.
//     Internally we push to a bounded queue (cap 500) and a separate
//     setInterval flusher batches up to 100 rows every ~2s.
//  3. Stream-level only. No per-frame rows. Allowed stages are listed
//     in ALLOWED_STAGES.
//  4. Leaf module. No imports from gemini-session.ts or server.ts.
//     Context flows in via parameters.
//  5. Heartbeat exactly once. Guarded against double-start.
// ============================================================

export const BUILD_VERSION = "2026-04-25-stable+voice-native-sms-rating";

export type LogContext = {
  call_sid?: string;
  conversation_id?: string;
  gemini_session_id?: string;
  cid?: string;
  caller_number?: string;
  did_number?: string;
};

const ALLOWED_STAGES = new Set<string>([
  "bridge_boot",
  "bridge_ready",
  "bridge_shutdown",
  "heartbeat",
  "sip_answer",
  "gemini_session_start",
  "gemini_session_ready",
  "media_stream_start",
  "first_inbound_audio",
  "first_outbound_audio",
  "vad_speech_start",
  "vad_speech_end",
  "media_stream_end",
  "gemini_session_end",
  "call_hangup",
  // back-compat aliases used by server.ts/gemini-session.ts in earlier code paths
  "audio_ws_connected",
  "jambonz_ws_open",
  "jambonz_ws_close",
  "prompt_cache_miss",
  "prompt_ready",
  "gemini_connect_start",
  "gemini_ready",
  "gemini_closed",
  "first_gemini_audio",
  "first_pstn_forward",
  "first_inbound_frame_seen",
  "prerecorded_greeting_sent",
  "escalation",
  // ── new in +logs-3 ──
  "user_turn_start",
  "user_turn_end",
  "model_first_audio",
  "model_turn_progress",
  "model_turn_complete",
  "model_interrupted",
  "transcription_unavailable",
  "turn_gap_alert",
  "greeting_sent",
  "greeting_suppress_canceled",
  "silence_probe_sent",
  "silence_timeout_hangup",
  "consent_granted",
  "consent_declined",
  "rating_captured",
  "rating_skipped",
  "telemetry_cap_reached",
]);

const LOGGER_ENABLED =
  (Deno.env.get("BRIDGE_REMOTE_LOGS") ?? "on").toLowerCase() !== "off";

const QUEUE_CAP = 500;
const BATCH_MAX = 100;
const FLUSH_INTERVAL_MS = 2000;
const WRITE_TIMEOUT_MS = 1500;
const HEARTBEAT_INTERVAL_MS = 45_000;

const INSTANCE_ID =
  (Deno.env.get("HOSTNAME") || "").trim() ||
  (typeof crypto !== "undefined" && crypto.randomUUID
    ? crypto.randomUUID()
    : `inst-${Date.now()}`);

const BASE_CONTEXT = {
  service: "gemini-bridge" as const,
  instance_id: INSTANCE_ID,
  pid: Deno.pid,
  build_version: BUILD_VERSION,
  env: "production",
};

type Level = "stage" | "info" | "warn" | "error";

interface QueuedRow {
  call_sid: string | null;
  cid: string | null;
  caller_number: string | null;
  did_number: string | null;
  level: Level;
  stage: string | null;
  message: string | null;
  elapsed_ms: number | null;
  metadata: Record<string, unknown>;
  created_at: string;
}

const queue: QueuedRow[] = [];
let droppedTotal = 0;
let totalFlushed = 0;
let lastWriteOkAt = "";
let lastWriteError = "";
let activeCallCount = 0;
let bridgeBootedAt = Date.now();
let started = false;
let heartbeatHandle: number | null = null;
let flushHandle: number | null = null;

function nowIso(): string {
  return new Date().toISOString();
}

export function setActiveCallCount(n: number): void {
  activeCallCount = n;
}

function pushRow(row: QueuedRow): void {
  if (!LOGGER_ENABLED) return;
  if (queue.length >= QUEUE_CAP) {
    queue.shift();
    droppedTotal += 1;
    if (droppedTotal % 50 === 1) {
      console.warn(`[logger] queue overflow dropped_total=${droppedTotal}`);
    }
  }
  queue.push(row);
}

function buildRow(
  level: Level,
  ctx: LogContext,
  stage: string | null,
  message: string | null,
  elapsedMs: number | null,
  extra: Record<string, unknown> | undefined,
): QueuedRow {
  const metadata: Record<string, unknown> = { ...BASE_CONTEXT };
  if (ctx.gemini_session_id) metadata.gemini_session_id = ctx.gemini_session_id;
  if (ctx.conversation_id) metadata.conversation_id = ctx.conversation_id;
  if (extra) Object.assign(metadata, extra);
  return {
    call_sid: ctx.call_sid ?? null,
    cid: ctx.cid ?? null,
    caller_number: ctx.caller_number ?? null,
    did_number: ctx.did_number ?? null,
    level,
    stage,
    message: message ? message.slice(0, 2000) : null,
    elapsed_ms: typeof elapsedMs === "number" ? elapsedMs : null,
    metadata,
    created_at: nowIso(),
  };
}

export function logStage(
  ctx: LogContext,
  stage: string,
  elapsedMs?: number,
  extra?: Record<string, unknown>,
): void {
  if (!ALLOWED_STAGES.has(stage)) {
    // Soft guard: log to console but still queue with a warn level so we notice.
    console.warn(`[logger] stage not in allow-list: ${stage}`);
  }
  pushRow(buildRow("stage", ctx, stage, null, elapsedMs ?? null, extra));
}

export function logInfo(
  ctx: LogContext,
  message: string,
  extra?: Record<string, unknown>,
): void {
  pushRow(buildRow("info", ctx, null, message, null, extra));
}

export function logWarn(
  ctx: LogContext,
  message: string,
  extra?: Record<string, unknown>,
): void {
  pushRow(buildRow("warn", ctx, null, message, null, extra));
}

export function logError(
  ctx: LogContext,
  message: string,
  extra?: Record<string, unknown>,
): void {
  pushRow(buildRow("error", ctx, null, message, null, extra));
}

// Back-compat: server.ts uses logEvent("warn"|"error"|"info", ctx, message, extra)
export function logEvent(
  level: "info" | "warn" | "error",
  ctx: LogContext,
  message: string,
  extra?: Record<string, unknown>,
): void {
  pushRow(buildRow(level, ctx, null, message, null, extra));
}

export function logHeartbeat(extra?: Record<string, unknown>): void {
  pushRow(
    buildRow(
      "stage",
      {},
      "heartbeat",
      null,
      null,
      {
        active_calls: activeCallCount,
        uptime_seconds: Math.floor((Date.now() - bridgeBootedAt) / 1000),
        last_supabase_write_at: lastWriteOkAt || null,
        last_write_error: lastWriteError || null,
        queue_size: queue.length,
        dropped_total: droppedTotal,
        total_flushed: totalFlushed,
        ...(extra ?? {}),
      },
    ),
  );
}

async function writeBatch(rows: QueuedRow[]): Promise<void> {
  if (!config.supabaseUrl || !config.supabaseServiceKey) {
    lastWriteError = "missing supabase url or service key";
    return;
  }
  const url = `${config.supabaseUrl}/rest/v1/voice_bridge_logs`;
  const writeFetch = fetch(url, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      apikey: config.supabaseServiceKey,
      Authorization: `Bearer ${config.supabaseServiceKey}`,
      Prefer: "return=minimal",
    },
    body: JSON.stringify(rows),
  }).then(async (res) => {
    if (!res.ok) {
      const txt = await res.text().catch(() => "");
      throw new Error(`status=${res.status} ${txt.slice(0, 200)}`);
    }
  });
  const timeout = new Promise<never>((_, reject) => {
    setTimeout(() => reject(new Error("write timeout")), WRITE_TIMEOUT_MS);
  });
  await Promise.race([writeFetch, timeout]);
}

async function flushOnce(): Promise<void> {
  if (!LOGGER_ENABLED || queue.length === 0) return;
  const batch = queue.splice(0, BATCH_MAX);
  try {
    await writeBatch(batch);
    lastWriteOkAt = nowIso();
    lastWriteError = "";
    totalFlushed += batch.length;
  } catch (err) {
    const msg = (err as Error).message;
    lastWriteError = msg;
    console.warn(
      `[logger] write failed dropped_batch=${batch.length} err=${msg}`,
    );
  }
}

export function startBridgeLogger(): void {
  if (started) return;
  started = true;
  bridgeBootedAt = Date.now();

  if (!LOGGER_ENABLED) {
    console.log("[logger] disabled via BRIDGE_REMOTE_LOGS=off");
    return;
  }

  // Boot row — proves to the admin UI that the new bundle is live.
  const envModel = Deno.env.get("GEMINI_MODEL");
  const resolvedModel = envModel || config.geminiModel;
  pushRow(
    buildRow(
      "stage",
      {},
      "bridge_boot",
      null,
      null,
      {
        manifest_mode: "stable",
        hostname: Deno.env.get("HOSTNAME") ?? null,
        deno_version: Deno.version.deno,
        supabase_url_set: Boolean(config.supabaseUrl),
        service_key_set: Boolean(config.supabaseServiceKey),
        gemini_model: resolvedModel,
        gemini_model_source: envModel ? "env" : "source-default",
        voice_name: config.voiceName,
      },
    ),
  );

  flushHandle = setInterval(() => {
    void flushOnce();
  }, FLUSH_INTERVAL_MS) as unknown as number;

  if (heartbeatHandle === null) {
    heartbeatHandle = setInterval(() => {
      logHeartbeat();
    }, HEARTBEAT_INTERVAL_MS) as unknown as number;
  }

  console.log(
    `[logger] enabled flush_every=${FLUSH_INTERVAL_MS}ms heartbeat_every=${HEARTBEAT_INTERVAL_MS}ms cap=${QUEUE_CAP} build=${BUILD_VERSION} instance=${INSTANCE_ID}`,
  );
}

config.ts:
/**
 * Gemini Bridge Configuration
 * Environment variables and constants for the Jambonz ↔ Gemini Live bridge.
 */

export const config = {
  // Server
  port: parseInt(Deno.env.get("PORT") || "3100", 10),
  tlsCertPath: Deno.env.get("TLS_CERT_PATH") || "",
  tlsKeyPath: Deno.env.get("TLS_KEY_PATH") || "",

  // Google Gemini
  googleApiKey: Deno.env.get("GOOGLE_CLOUD_API_KEY") || "",
  geminiModel: "models/gemini-3.1-flash-live-preview",
  geminiWsBase:
    "wss://generativelanguage.googleapis.com/ws/google.ai.generativelanguage.v1beta.GenerativeService.BidiGenerateContent",

  // Supabase
  supabaseUrl: Deno.env.get("SUPABASE_URL") || "",
  supabaseServiceKey: Deno.env.get("SUPABASE_SERVICE_ROLE_KEY") || "",

  // Voice config
  voiceName: Deno.env.get("GEMINI_VOICE") || "Aoede",
  maxKbArticles: 20,

  // Escalation
  escalationKeywords: [
    "transfer to agent",
    "speak to a person",
    "talk to human",
    "connect me to",
    "real person",
    "human agent",
    "ขอคุยกับเจ้าหน้าที่",
    "ขอคุยกับคน",
    "ต่อสายให้หน่อย",
  ],
  escalationTransferNumber: Deno.env.get("ESCALATION_TRANSFER_NUMBER") || "",

  // Bridge external URL
  bridgeExternalUrl: Deno.env.get("BRIDGE_EXTERNAL_URL") || "ws://localhost:3100",

  // Jambonz audio format
  jambonzSampleRate: 16000,
  jambonzEncoding: "L16",

  // ── Voice-native add-ons (all OFF by default; enable per-feature) ──
  smsEnabled: Deno.env.get("VOICE_SMS_ENABLED") === "1",
  ratingEnabled: Deno.env.get("VOICE_RATING_ENABLED") === "1",
  memoryEnabled: Deno.env.get("VOICE_MEMORY_ENABLED") === "1",
  silenceProbeGuardEnabled:
    Deno.env.get("VOICE_SILENCE_PROBE_GUARD_ENABLED") === "1",
  ratingWindowMs: parseInt(Deno.env.get("VOICE_RATING_WINDOW_MS") || "60000", 10),
  silenceProbeGuardMs: parseInt(
    Deno.env.get("VOICE_SILENCE_PROBE_GUARD_MS") || "5000",
    10,
  ),

  // SMS via Supabase edge function (uses ALARIS_* secrets server-side)
  voiceSmsFnPath: "/functions/v1/voice-send-sms",
};

export function validateConfig(): void {
  const missing: string[] = [];

  if (!config.googleApiKey) missing.push("GOOGLE_CLOUD_API_KEY");
  if (!config.supabaseUrl) missing.push("SUPABASE_URL");
  if (!config.supabaseServiceKey) missing.push("SUPABASE_SERVICE_ROLE_KEY");

  if (missing.length > 0) {
    throw new Error(`Missing required env vars: ${missing.join(", ")}`);
  }
}
